commit e302fa89aa45afceedb711a264cfc486395aca17
Author: Florian Hahn <flo@fhahn.com>
Date:   Tue Oct 18 15:12:23 2022 +0100

    [LoopUnroll] Forget exit values when making changes.

    When unrolling, the exit values in LCSSA phis will get updated.
    Invalidate cached SCEV values for those phis in case SCEV looked through
    a exit phi.

    Fixes #58340.

diff --git a/llvm/lib/Transforms/Utils/LoopUnroll.cpp b/llvm/lib/Transforms/Utils/LoopUnroll.cpp
index 6d6c3db034ca..fd874db6981b 100644
--- a/llvm/lib/Transforms/Utils/LoopUnroll.cpp
+++ b/llvm/lib/Transforms/Utils/LoopUnroll.cpp
@@ -578,6 +578,7 @@ LoopUnrollResult llvm::UnrollLoop(Loop *L, UnrollLoopOptions ULO, LoopInfo *LI,
           if (It != LastValueMap.end())
             Incoming = It->second;
           PHI.addIncoming(Incoming, New);
+          SE->forgetValue(&PHI);
         }
       }
